/* Clear All confirmation modal */
.confirm-modal {
  position: fixed;
  inset: 0;
  display: none;
  align-items: center;
  justify-content: center;
  padding: 24px;
  background: rgba(8, 20, 34, 0.42);
  backdrop-filter: blur(4px);
  z-index: 1300;
}

.confirm-modal.active {
  display: flex;
}

.confirm-card {
  width: min(420px, 100%);
  padding: 22px;
  border-radius: 24px;
  background: #ffffff;
  border: 1px solid rgba(197, 208, 220, 0.9);
  box-shadow: 0 26px 70px rgba(8, 20, 34, 0.24);
  color: #102033;
  animation: confirmCardIn 0.18s ease both;
}

@keyframes confirmCardIn {
  from { opacity: 0; transform: translateY(8px) scale(0.985); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}

.confirm-kicker {
  margin-bottom: 8px;
  font-size: 11px;
  font-weight: 820;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #8a2d1c;
}

.confirm-card h2 {
  margin: 0 0 8px;
  font-size: 22px;
  line-height: 1.15;
  letter-spacing: -0.025em;
}

.confirm-card p {
  margin: 0;
  color: #5d6b7c;
  line-height: 1.48;
  font-size: 14.5px;
}

.confirm-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 20px;
}

.confirm-actions button {
  min-height: 42px;
  border-radius: 999px;
  padding: 0 16px;
  font-weight: 760;
}

.confirm-actions .btn-danger {
  background: #fbe7e2;
  color: #8a2d1c;
}

.confirm-actions .btn-danger:hover {
  background: #f7d2c8;
}

